// SPDX-License-Identifier: GPL-3.0-only
pragma solidity >=0.8.3;

/// @dev The precompiled address of the Proof verifier contract on the Ethereum network.
address constant PROOF_VERIFIER_ADDRESS = 0x0000000000000000000000000000000000000Be9;

/// @dev Instance of the QueryVerifierContract interface at the precompiled address.
QueryVerifierContract constant CLAIM_CONTRACT_ADRRESS = QueryVerifierContract(
    PROOF_VERIFIER_ADDRESS
);

type QueryId is bytes32;

struct Query {
    uint64 chainId;
    uint64 height;
    uint64 index;
    LayoutSegment[] layout;
}

struct LayoutSegment {
    uint64 offset;
    uint64 size;
}

struct ResultSegment {
    uint256 offset; // potentially not needed due to ordering
    bytes abiBytes;
}

enum VerifierExitStatus {
    Success,
    ProofInvalid,
    LayoutMismatch,
    QueryOutOfBounds
}

struct VerifierResult {
    VerifierExitStatus status;
    ResultSegment[] resultSegments;
}

/// @title ProofVerifierContract interface
/// @notice This interface defines the functions and events for interacting with the ProofVerifierContract.
interface QueryVerifierContract {
    /// @notice Submit proof for a query.
    /// @param proof The proof to be submitted.
    /// @param query The query to be verified.
    function verify(
        bytes calldata proof,
        Query calldata query
    ) external returns (VerifierResult memory);
}

// SPDX-License-Identifier: GPL-3.0-only
pragma solidity >=0.8.3;

/// @dev The SignatureVerifier precompile address
address constant SIGNATURE_VERIFIER_ADDRESS = 0x00000000000000000000000000000000000013B9;

SignatureVerifier constant SIGNATURE_VERIFIER_CONTRACT = SignatureVerifier(SIGNATURE_VERIFIER_ADDRESS);

/// @title SignatureVerifier interface
/// @notice This interface defines the function for verifying Substrate sr25519 signatures.
interface SignatureVerifier {
    /// @dev Verifies an sr25519 signature.
    /// @param message The message that was signed.
    /// @param signature The 64-byte sr25519 signature.
    /// @param publicKey The 32-byte sr25519 public key.
    /// @return bool true if the signature is valid, false otherwise.
    function verify(bytes calldata message, bytes calldata signature, bytes32 publicKey) external view returns (bool);
}

// SPDX-License-Identifier: GPL-3.0-only
pragma solidity >=0.8.3;

/// @dev The Deposit precompile address
address constant SUBSTRATE_TRANSFER_ADDRESS = 0x0000000000000000000000000000000000000Fd1;

SubstrateTransfer constant SUBSTRATE_TRANSFER_ADRRESS = SubstrateTransfer(SUBSTRATE_TRANSFER_ADDRESS);

/// @title SubstrateTransfer interface
interface SubstrateTransfer {
    /// @dev Event emitted when a transfer has been performed.
    /// @param destination The Substrate address receiving the tokens.
    /// @param amount The amount of tokens transferred.
    event Transfer(bytes32 destination, uint256 amount);

    /// @dev Function to transfer tokens to a Substrate address.
    /// @param destination The Substrate address receiving the tokens.
    /// @param amount The amount of tokens to transfer.
    function transfer_substrate(bytes32 destination, uint256 amount) external;
}
